mapper.select:
    select * from (
	    select * from management_history
	    where user_id = #{userId}
	    order by update_date desc
	)
	WHERE rownum = 1

    select * from (
	    select * from management_history
	    where sub_index = #{subIndex}
	    and type=#{type}
	    order by update_date desc
	)
	WHERE rownum = 1
